import hashlib
from bisect import insort, bisect_left, bisect_right

def consistent_hash_router(operations):
    RING_SIZE = 2 ** 32

    def md5_hash(s):
        return int(hashlib.md5(s.encode()).hexdigest(), 16) % RING_SIZE

    ring_positions = []
    ring_map = {}
    node_vnodes = {}
    key_hashes = {}
    key_node = {}
    results = []

    def find_node(pos):
        if not ring_positions:
            return "NONE"
        idx = bisect_right(ring_positions, pos)
        if idx == len(ring_positions):
            idx = 0
        return ring_map[ring_positions[idx]]

    for op in operations:
        cmd = op[0]
        if cmd == "ADD":
            node_name, num_v = op[1], op[2]
            positions = []
            for i in range(num_v):
                h = md5_hash(f"{node_name}#{i}")
                positions.append(h)
                insort(ring_positions, h)
                ring_map[h] = node_name
            node_vnodes[node_name] = positions
            moved = []
            for key, kh in key_hashes.items():
                new_node = find_node(kh)
                if new_node != key_node[key]:
                    moved.append((key, new_node))
                    key_node[key] = new_node
            moved.sort()
            results.append(moved)
        elif cmd == "REMOVE":
            node_name = op[1]
            for pos in node_vnodes[node_name]:
                idx = bisect_left(ring_positions, pos)
                ring_positions.pop(idx)
                del ring_map[pos]
            del node_vnodes[node_name]
            moved = []
            for key, kh in key_hashes.items():
                new_node = find_node(kh)
                if new_node != key_node[key]:
                    moved.append((key, new_node))
                    key_node[key] = new_node
            moved.sort()
            results.append(moved)
        elif cmd == "STORE":
            key = op[1]
            h = md5_hash(key)
            key_hashes[key] = h
            node = find_node(h)
            key_node[key] = node
            results.append(node)
        elif cmd == "LOOKUP":
            key = op[1]
            results.append(find_node(md5_hash(key)))
        elif cmd == "COUNT":
            counts = {node: 0 for node in node_vnodes}
            for key, node in key_node.items():
                if node in counts:
                    counts[node] += 1
            results.append(counts)
    return results
